UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES
('f2cc7fb6-ebf2-43e8-b887-9ee2cc2c5487'::uuid, 'La bronchite entraîne un encombrement des voies respiratoires, les huiles essentielles en inhalation aident à dégager les bronches pour respirer mieux.'),
('4e3f8ef4-4792-4347-8ce0-44bd7290c799'::uuid, 'La brûlure lèse la peau, cette émulsion favorise la réparation cutanée et réduit la douleur liée à l''inflammation.'),
('6ae9f6f7-193c-4bf0-b652-bbfec680727a'::uuid, 'La brûlure entraîne une lésion cutanée, la trolamine aide à apaiser la zone et favorise la cicatrisation épidermique.'),
('386eceec-8cc7-46b0-be1b-914f12ee6065'::uuid, 'Une brûlure nécessite une régénération cutanée, le pansement hydrocolloïde maintient un milieu humide optimal pour une meilleure cicatrisation.'),
('4179dbd8-2649-4cbc-8860-a93936f7d012'::uuid, 'Des brûlures d''estomac sont dues à l''acidité gastrique, le pansement gastrique forme une barrière protectrice sur la muqueuse.'),
('e3d03510-83e0-48c9-9ca7-dc238c47ec04'::uuid, 'Les brûlures d''estomac proviennent d''un excès d''acidité, le bicarbonate aide à neutraliser l''acidité gastrique excessive.'),
('2b240e15-8725-4681-bcc2-8c7c7cd9cfc1'::uuid, 'Les brûlures d''estomac sont liées à une irritation gastrique, la tisane digestive apaise la muqueuse pour réduire cette sensation.'),
('907d23ff-c0b7-4bc6-9b52-42eec5e9226e'::uuid, 'Les brûlures d''estomac irritent la muqueuse gastrique, le pansement gastrique crée une protection pour un soulagement rapide.'),
('a4513bbc-07cc-4212-bbac-88e784f10ec3'::uuid, 'Des brûlures d''estomac peuvent être dues à une digestion difficile, ce complément favorise la dégradation des aliments pour les réduire.'),
('fe6d2070-6892-4483-b875-3ce5c709c49f'::uuid, 'L''acidité gastrique cause les brûlures d''estomac, l''eau bicarbonatée aide à neutraliser cet excès pour un soulagement rapide.'),
('7f069404-60b3-435c-a359-4db0902c2e53'::uuid, 'La candidose est une infection fongique focale, l''antifongique buccal agit localement pour éliminer le champignon responsable.'),
('c24b093a-814e-491c-af01-7790e05fe0da'::uuid, 'La candidose se développe en milieu acide, le bain de bouche au bicarbonate alcalinise la cavité pour freiner sa prolifération.'),
('0b99c352-4b3d-432e-9180-8eec704dcce5'::uuid, 'La candidose buccale est due à un déséquilibre de la flore, les probiotiques rétablissent une flore saine pour prévenir les récidives.'),
('1ae9aed5-e6f9-47fd-afba-acce78c50429'::uuid, 'La candidose vaginale est une infection mycosique, l''ovule antifongique agit localement pour détruire les champignons.'),
('233384e9-447a-49f7-96d8-5f34ae31c2fb'::uuid, 'La candidose vaginale irrite la muqueuse, le gel intime pH neutre respecte l''équilibre microbien et cutané.'),
('33eda54d-6219-4730-92df-0eb011c1344b'::uuid, 'La candidose vaginale déséquilibre la flore, les probiotiques vaginaux aident à restaurer la flore de Döderlein pour prévenir les récidives.'),
('5c34f700-bb51-4e5c-8a82-51a1441c75ea'::uuid, 'Une carence en acide folique peut entraîner une fatigue générale, la vitamine D3 soutient le système immunitaire et la santé osseuse.'),
('9018643e-fbd9-4883-82a3-cc661302def9'::uuid, 'Une carence en acide folique peut impacter la vitalité, la vitamine D3 renforce le système immunitaire et la structure osseuse.'),
('ac21fda7-a52c-4760-b55c-3adc85dbcc8e'::uuid, 'La carence en folates affecte la division cellulaire, la vitamine D3 joue un rôle essentiel dans le bon fonctionnement immunitaire et osseux.'),
('d0f20f2d-f551-447e-9741-bedc8552190b'::uuid, 'Le fer est mal absorbé dans l''intestin, la vitamine C améliore significativement l''assimilation du fer pour combattre l''anémie.'),
('7830632f-c0bd-45d0-a9af-b483551517a0'::uuid, 'La carence en fer provoque une anémie, le fer bisglycinate a une haute biodisponibilité pour mieux reconstituer les réserves.'),
('b7fcc7c0-9573-42f0-bcff-5b86128dd51c'::uuid, 'La carence en fer fatigue l''organisme, la spiruline apporte du fer assimilable pour améliorer le transport d''oxygène.'),
('bc967403-bdb9-46d5-939d-aafa4b49a62b'::uuid, 'Une carence en B12 altère la formation des globules rouges, l''apport sublingual de méthylcobalamine assure une absorption rapide.'),
('6884c517-1701-453e-93a5-02c248fc27cc'::uuid, 'La carence en vitamine B12 affecte l''énergie, un complexe de vitamines B soutient le métabolisme cellulaire pour retrouver la vitalité.'),
('12a6e5fb-702e-48f9-b5cb-73490673db78'::uuid, 'La carence en B12 impacte l''énergie et la neurologie, la spiruline fournit des cofacteurs essentiels pour le métabolisme cellulaire.'),
('ff4d7bc5-0986-4bc5-a18e-45497793348d'::uuid, 'La carence en vitamine D perturbe le métabolisme du calcium, une supplémentation adaptée corrige ce déficit pour la santé osseuse.'),
('548c763f-5b03-434c-8960-321900f91590'::uuid, 'La carence en vitamine D affecte l''ossification, la vitamine K2 dirige le calcium vers les os pour renforcer la structure osseuse.'),
('3d1db626-0d7c-4a05-b78e-fdb72b17a035'::uuid, 'Les céphalées de tension provoquent des douleurs locales, le stick menthe poivrée procure une sensation de froid pour masquer la douleur.'),
('0cffb2c9-6b71-4d9f-9552-6d1eef4d88ad'::uuid, 'Les céphalées de tension sont souvent liées à un stress musculaire, le magnésium réduit la tension musculaire pour soulager la douleur.'),
('54f15be6-99ca-4d3d-9975-14369c544ad5'::uuid, 'Les céphalées peuvent provoquer une tension locale, ce baume aide à décontracter les muscles et diminuer la douleur.'),
('b9785dbd-d7b0-4762-93e6-c5eca86ebfa8'::uuid, 'Le chalazion est une inflammation glandulaire, la chaleur aide à fluidifier les sécrétions et désengorger la paupière.'),
('d214e309-bce6-49c0-87ba-54e579f0365c'::uuid, 'Le chalazion peut s''infecter, ces lingettes aident à nettoyer la zone et réduire le risque de surinfection bactérienne.'),
('fe8c55d3-ac41-47f1-9641-77066c335bc3'::uuid, 'Après un choc anaphylactique, un soutien nutritionnel est important pour la récupération cellulaire générale.'),
('0166ad80-184f-4b09-9f49-8c6bb882fca5'::uuid, 'Après un choc anaphylactique, un apport en minéraux peut soutenir les fonctions neuromusculaires pour une meilleure récupération.'),
('6563eb42-ff6a-4aa7-8338-bd79ace75260'::uuid, 'Après un choc anaphylactique, soutenir la flore intestinale aide à restaurer l''équilibre digestif et immunitaire.'),
('bdf47dc1-f9bc-416b-a48f-4ff8bd621f6d'::uuid, 'La chute de cheveux est souvent liée à une fragilité du follicule, ce complément renforce la kératine et la croissance capillaire.'),
('27f0c267-a446-46a4-91ab-1eda0a8eaf75'::uuid, 'La chute de cheveux est souvent liée à une carence, ce complément apporte kératine et vitamines pour fortifier le cheveu.'),
('1a2a7192-a1e5-4704-9bea-ca915b3518f1'::uuid, 'Une carence en biotine peut fragiliser le cheveu, cette vitamine aide à soutenir la santé capillaire et des phanères.'),
('e8029c09-bca9-494f-ada6-c6a58757368e'::uuid, 'Les cicatrices sont vulnérables aux UV, la crème solaire aide à prévenir l''hyperpigmentation post-inflammatoire.'),
('85fb50df-fcc5-4eca-9499-2e596f1188da'::uuid, 'La peau cicatrisée est fragile, cette crème favorise la réparation tissulaire et l''hydratation de l''épiderme.'),
('7b3e93a9-9ec8-4dde-aeb4-612e0b69d02b'::uuid, 'Les cicatrices peuvent être inesthétiques, le gel silicone améliore l''apparence en réduisant la fibrose et l''épaisseur.'),
('5b4e0bf3-0913-4a91-bca5-c7beb2786d48'::uuid, 'Après une colique néphrétique, les probiotiques aident à restaurer l''équilibre de la flore intestinale.'),
('c3606e54-aa8d-4372-862e-84a10e464506'::uuid, 'Les coliques néphrétiques provoquent de fortes douleurs spasmodiques, la chaleur aide à détendre les muscles et calmer les spasmes.'),
('ada5f19d-fe4b-495b-8ebd-6076a3874fc8'::uuid, 'Après une colique néphrétique, le charbon végétal aide à absorber les gaz intestinaux et réduire les ballonnements associés.'),
('ddef7751-cafb-4e5e-8aaa-8740d095c795'::uuid, 'Les coliques du nourrisson sont souvent liées à une immaturité digestive, cette solution soutient la digestion et apaise le ventre.'),
('96861f45-db30-437b-a860-314864ef935b'::uuid, 'Les coliques du nourrisson sont souvent dues aux gaz, ce produit aide à réduire les bulles de gaz et les ballonnements.'),
('1d4951f5-e074-4053-a6a6-4257a891363f'::uuid, 'Les coliques du nourrisson peuvent être liées à un déséquilibre de la flore, ces probiotiques aident à améliorer la digestion.'),
('320f9fdc-2927-435b-9dd9-f52d3d9414f2'::uuid, 'La congestion nasale est due à un œdème de la muqueuse, le spray hypertonique décongestionne par effet osmotique naturel.'),
('6e3fff6a-e6c5-4d13-a76c-843abf2df8c1'::uuid, 'La congestion nasale provient d''une muqueuse gonflée, le spray hypertonique aide à réduire l''œdème et faciliter la respiration.'),
('0a8050ec-5eda-493c-a787-8b5359a3ebea'::uuid, 'La congestion nasale obstrue les voies respiratoires, l''inhalation d''huiles essentielles aide à libérer les bronches.')
) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;